const inp = ($json && typeof $json === 'object') ? $json : {};
const S = function(v){ return String(v==null?'':v).trim(); };
const title = S(inp.title) || '(제목 없음)';
const occurredAt = S(inp.occurredAt);
const service = S(inp.service);
const severity = S(inp.severity);
const status = S(inp.status);
const symptom = S(inp.symptom);
const cause = S(inp.cause);
const action = S(inp.action);
const followup = S(inp.followup);
const reporter = S(inp.reporter);
const logRefs = S(inp.logRefs);
const sourceLink = S(inp.sourceLink);
const trust = S(inp.trust);
const SERVICES = ['wings-api','bomapp-api','mydata-api','mydata-agent','chat-api','open-api','next-frontend','infra','기타'];
const SEV = ['Critical','High','Medium','Low'];
const STT = ['발생 중','복구 완료','후속 조치 중'];
const TRUST = ['확정','AI추가','검토필요'];
const sev = SEV.indexOf(severity) >= 0 ? severity : 'Medium';
const st = STT.indexOf(status) >= 0 ? status : '발생 중';
const start = occurredAt || new Date().toISOString();
const props = {};
props['제목'] = { title: [{ text: { content: title.slice(0,2000) } }] };
props['발생일시'] = { date: { start: start } };
props['서비스/API'] = { select: { name: SERVICES.indexOf(service) >= 0 ? service : '기타' } };
props['심각도'] = { select: { name: sev } };
props['상태'] = { select: { name: st } };
props['신뢰등급'] = { select: { name: TRUST.indexOf(trust) >= 0 ? trust : 'AI추가' } };
if (cause) props['원인 요약'] = { rich_text: [{ text: { content: cause.slice(0,2000) } }] };
if (action) props['조치 내용'] = { rich_text: [{ text: { content: action.slice(0,2000) } }] };
if (followup) props['후속 과제'] = { rich_text: [{ text: { content: followup.slice(0,2000) } }] };
const h2 = function(t){ return { object:'block', type:'heading_2', heading_2:{ rich_text:[{ type:'text', text:{ content: String(t).slice(0,1900) } }] } }; };
const para = function(t){ return { object:'block', type:'paragraph', paragraph:{ rich_text:[{ type:'text', text:{ content: String(t).slice(0,1900) } }] } }; };
const bullet = function(t){ return { object:'block', type:'bulleted_list_item', bulleted_list_item:{ rich_text:[{ type:'text', text:{ content: String(t).slice(0,1900) } }] } }; };
const blocks = [];
blocks.push(h2('개요'));
blocks.push(bullet('발생 시점: ' + start));
blocks.push(bullet('영향 서비스/API: ' + (service || '미상')));
blocks.push(bullet('심각도: ' + sev + ' / 상태: ' + st));
if (reporter) blocks.push(bullet('보고자/담당: ' + reporter));
const addSec = function(t, body){ blocks.push(h2(t)); blocks.push(para(body ? body : '(미기재)')); };
addSec('증상', symptom);
addSec('원인', cause);
addSec('조치', action);
addSec('후속 과제', followup);
if (logRefs) {
  blocks.push(h2('🔎 관련 로그·메트릭 (Elasticsearch)'));
  const lines = logRefs.split(String.fromCharCode(10)).map(function(s){ return s.trim(); }).filter(function(s){ return s; });
  (lines.length ? lines : ['(기재 없음)']).forEach(function(l){ blocks.push(bullet(l)); });
}
if (sourceLink) { blocks.push({ object:'block', type:'divider', divider:{} }); blocks.push(para('출처: ' + sourceLink)); }
const payload = { parent: { database_id: 'cecdb9670ad04e2eab141221cb27b52a' }, properties: props, children: blocks };
return [{ json: { payload: payload } }];

const r = $json || {};
if (r.id) return [{ json: { ok:true, text: '장애 기록 생성 완료. id=' + r.id + (r.url ? (' url=' + r.url) : '') } }];
const msg = r.message || (r.error && r.error.message) || JSON.stringify(r).slice(0,400);
return [{ json: { ok:false, text: '장애 기록 생성 실패: ' + msg } }];
